export default QuestionBuilder;

import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';
import { questions as importedQuestions } from './data';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);

  // Load custom questions from local storage
  const [customQuestions, setCustomQuestions] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_custom_questions');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load custom questions", e);
      return [];
    }
  });

  // Save to local storage whenever custom questions change
  useEffect(() => {
    localStorage.setItem('anatomy_custom_questions', JSON.stringify(customQuestions));
  }, [customQuestions]);

  const handleAddQuestion = (q: Question) => {
    setCustomQuestions(prev => [q, ...prev]);
  };

  const handleDeleteQuestion = (id: string) => {
    if (confirm("Are you sure you want to delete this question?")) {
      setCustomQuestions(prev => prev.filter(q => q.id !== id));
    }
  };

  // Merge static and custom questions
  const allQuestions = useMemo(() => {
    return [...importedQuestions, ...customQuestions];
  }, [customQuestions]);

  // Extract all available categories for the builder autocomplete
  const categories = useMemo(() => {
    const cats = new Set(importedQuestions.map(q => q.category || 'General'));
    customQuestions.forEach(q => cats.add(q.category || 'General'));
    return Array.from(cats).sort();
  }, [customQuestions]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
      <Header currentMode={currentMode} onModeChange={setCurrentMode} />

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block py-6' : 'hidden'}>
          <QuestionList data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.BUILDER ? 'block py-6' : 'hidden'}>
          <QuestionBuilder 
            customQuestions={customQuestions} 
            onAdd={handleAddQuestion}
            onDelete={handleDeleteQuestion}
            existingCategories={categories}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

