  existingCategories: string[];
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ customQuestions, onAdd, onUpdate, onDelete, existingCategories }) => {
  const [editingId, setEditingId] = useState<string | null>(null);

