    e.preventDefault();
    if (!formData.questionText || !formData.answerText || !formData.category) return;

    if (editingId) {
      // Update existing
      const updatedQuestion: Question = {
        id: editingId,
        ...formData,
        options: [] 
      };
      onUpdate(updatedQuestion);
      setEditingId(null);
    } else {
      // Create new
      const newQuestion: Question = {
        id: `custom-${Date.now()}`,
        ...formData,
        options: [] 
      };
      onAdd(newQuestion);
    }

    // Reset form but keep category for convenience
    setFormData(prev => ({
      category: prev.category,
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: ''
    }));
  };

