        </form>
      </div>

      {/* List of Custom Questions */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-bold text-slate-700 flex items-center gap-2">
            My Custom Questions
            <span className="bg-violet-100 text-violet-700 text-xs px-2 py-1 rounded-full">{customQuestions.length}</span>
          </h3>
        </div>

        {customQuestions.length === 0 ? (
          <div className="text-center p-12 bg-slate-100 rounded-xl border-2 border-dashed border-slate-200 text-slate-400">
            <p className="font-medium">No custom questions added yet.</p>
            <p className="text-sm">Use the form above to get started.</p>
