        ) : (
          <div className="grid gap-4">
            {customQuestions.map((q) => (
              <div key={q.id} className={`bg-white p-4 rounded-xl border shadow-sm flex flex-col md:flex-row gap-4 items-start justify-between group transition-colors ${editingId === q.id ? 'border-amber-400 ring-2 ring-amber-100' : 'border-slate-200 hover:border-violet-300'}`}>
                <div className="flex-1 space-y-2 w-full">
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-violet-600 bg-violet-50 px-2 py-0.5 rounded border border-violet-100">
                      {q.category}
                    </span>
                  </div>
                  {/* HTML Rendering in List */}
                  <h4 
                    className="font-bold text-slate-800"
                    dangerouslySetInnerHTML={{ __html: q.questionText }}
                  />
                  <div className="text-sm text-slate-600 border-l-2 border-emerald-400 pl-3">
                    <span dangerouslySetInnerHTML={{ __html: q.answerText }} />
                  </div>
                  {q.explanation && (
                    <p className="text-xs text-slate-400 italic mt-1" dangerouslySetInnerHTML={{ __html: q.explanation }} />
                  )}
                </div>
                <div className="flex gap-2 shrink-0 self-end md:self-start">
                  <button
                    onClick={() => handleEdit(q)}
                    className="p-2 text-slate-400 hover:text-amber-600 hover:bg-amber-50 rounded-lg transition-colors"
                    title="Edit Question"
                  >
                    <Pencil size={18} />
                  </button>
                  <button
                    onClick={() => onDelete(q.id)}
                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    title="Delete Question"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

