import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { Shuffle, RotateCcw, Image as ImageIcon, CircleAlert, Eye, EyeOff, ChevronLeft, ChevronRight, Volume2, VolumeX, Lightbulb, Filter, Check, X, ChevronDown } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  // Filter State
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  // New Audio Hook
  const { speak, cancel, isSpeaking, activeType } = useSpeech();

  // Extract categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    // Filter logic
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  useEffect(() => {
    cancel();
  }, [isFlipped, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const nextCard = () => {
    if (currentIndex < deck.length - 1 && !isAnimating) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 200);
    }
  };

  const prevCard = () => {
    if (currentIndex > 0 && !isAnimating) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 200);
    }
  };

  const shuffleDeck = () => {
    setIsFlipped(false);
    setTimeout(() => {
      const shuffled = [...deck].sort(() => Math.random() - 0.5);
      setDeck(shuffled);
      setCurrentIndex(0);
    }, 200);
  };

  const flipCard = () => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(!isFlipped);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const currentCard = deck[currentIndex];

  // Helper to strip HTML for speech
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  return (
    <div className="flex flex-col items-center justify-center max-w-3xl mx-auto w-full px-4 py-8">
      {/* Controls Header */}
      <div className="w-full flex flex-col md:flex-row justify-between items-center mb-6 gap-4 px-2 relative z-20">
        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm order-2 md:order-1">
          {deck.length > 0 ? `Card ${currentIndex + 1} / ${deck.length}` : '0 Cards'}
        </span>

        <div className="flex items-center gap-2 order-1 md:order-2">
          {/* Filter Dropdown */}
          <div className="relative">
            <Button 
              variant="ghost" 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`flex items-center gap-2 text-xs font-bold rounded-lg transition-colors border ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white text-slate-500 border-slate-200 hover:text-blue-600'}`}
            >
              <Filter size={14} />
              {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'Filter Topics'}
              <ChevronDown size={12} className={`transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
            </Button>

            {isFilterOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                <div className="absolute right-0 top-full mt-2 w-64 md:w-80 bg-white border border-slate-200 rounded-xl shadow-xl z-20 overflow-hidden flex flex-col max-h-[60vh] animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center shrink-0">
                    <span className="text-xs font-bold text-slate-500 uppercase">Select Categories</span>
                    <button 
                      onClick={() => setSelectedCategories([])}
                      className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase hover:bg-red-50 px-2 py-1 rounded"
                    >
                      Clear All
                    </button>
                  </div>
                  <div className="overflow-y-auto p-2 custom-scrollbar">
                    {categories.map(cat => (
                      <label key={cat} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group transition-colors">
                        <div className="checkbox-wrapper relative w-4 h-4 shrink-0">
                          <input 
                            type="checkbox" 
                            className="peer appearance-none w-full h-full border border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                            checked={selectedCategories.includes(cat)}
                            onChange={() => toggleCategory(cat)}
                          />
                          <Check size={10} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                        </div>
                        <span className={`text-sm font-medium transition-colors ${selectedCategories.includes(cat) ? 'text-blue-700' : 'text-slate-600 group-hover:text-slate-900'}`}>
                          {cat}
                        </span>
                      </label>
                    ))}
                  </div>
                  <div className="p-2 border-t border-slate-100 bg-slate-50 shrink-0">
                    <button 
                      onClick={() => setIsFilterOpen(false)}
                      className="w-full py-2 bg-slate-900 text-white rounded-lg text-xs font-bold uppercase tracking-wide hover:bg-slate-800 transition-colors"
                    >
                      Done
                    </button>
                  </div>
                </div>
              </>
            )}
          </div>

          <div className="w-px h-6 bg-slate-300 mx-1"></div>

          <Button 
            variant="ghost" 
            onClick={shuffleDeck} 
            title="Shuffle Deck"
            disabled={deck.length <= 1}
            className="flex items-center gap-2 text-xs font-bold text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-100"
          >
            <Shuffle size={14} /> Shuffle
          </Button>
        </div>
      </div>

      {/* Card Container */}
      {deck.length > 0 ? (
        <div className="relative w-full aspect-[4/5] sm:aspect-[4/3] md:aspect-[16/9] cursor-pointer perspective-1000 z-10" onClick={flipCard}>
          <div className={`
              w-full h-full relative transform-style-3d transition-transform duration-500 ease-in-out
              ${isFlipped ? 'rotate-y-180' : ''}
            `}>

            {/* Front Side (Question) */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-xl shadow-md border border-slate-200 backface-hidden flex flex-col overflow-hidden">
              <div className="px-6 pt-6 flex justify-between items-start">
                <div className="flex flex-col">
                  <span className="text-xs font-bold uppercase tracking-wider text-red-500 mb-1">Question</span>
                  <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider bg-slate-50 px-2 py-0.5 rounded border border-slate-100 w-fit">
                    {currentCard.category || 'General'}
                  </span>
                </div>
                <div className="flex items-center gap-2 text-slate-300">
                  <button 
                    onClick={(e) => speak(stripHtml(currentCard.questionText), 'question-main', 'question', e)}
                    className={`p-2 rounded-full transition-all duration-300 ${isSpeaking && activeType === 'question' ? 'text-blue-600 bg-blue-50 scale-110 ring-2 ring-blue-100 animate-pulse' : 'text-slate-400 hover:bg-slate-100 hover:text-blue-600'}`}
                    title={isSpeaking && activeType === 'question' ? "Stop Reading" : "Read Question"}
                  >
                    {isSpeaking && activeType === 'question' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                  </button>
                  <RotateCcw size={16} />
                </div>
              </div>

              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && (
                  <div className="flex-shrink-0 w-full flex items-center justify-center mb-6">
                    {imgError ? (
                      <div className="flex flex-col items-center justify-center p-6 bg-slate-50 rounded-lg border border-slate-200 text-slate-400 gap-2">
                        <ImageIcon size={24} />
                        <span className="text-xs font-medium">Image not available</span>
                      </div>
                    ) : (
                      <div className="p-2 bg-white rounded-lg border border-slate-100 shadow-sm max-h-[200px] overflow-hidden">
                        <img 
                          src={currentCard.questionImage} 
                          alt="Question" 
                          className="max-h-[180px] w-auto object-contain"
                          onError={() => setImgError(true)}
                        />
                      </div>
                    )}
                  </div>
                )}
                {/* Render Question as HTML */}
                <div 
                  className={`text-xl md:text-2xl font-bold text-center text-slate-800 leading-relaxed ${currentCard.questionImage ? '' : 'mt-4'}`}
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText || "Identify this item" }}
                />
              </div>

              <div className="h-10 flex items-center justify-center text-[10px] font-bold text-slate-300 uppercase tracking-widest pb-2">
                Click to reveal answer
              </div>
            </div>

            {/* Back Side (Answer) */}
            <div className="absolute inset-0 w-full h-full bg-slate-800 rounded-xl shadow-md border border-slate-700 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-6 pt-6 flex justify-between items-center border-b border-slate-700/50 pb-4">
                <span className="text-xs font-bold uppercase tracking-wider text-blue-400">Answer</span>
                <div className="flex items-center gap-2 text-slate-600">
                  <button 
                    onClick={(e) => speak(stripHtml(currentCard.answerText) + (currentCard.explanation ? `. Note: ${stripHtml(currentCard.explanation)}` : ''), 'answer-main', 'answer', e)}
                    className={`p-2 rounded-full transition-all duration-300 ${isSpeaking && activeType === 'answer' ? 'text-blue-400 bg-white/10 scale-110 ring-1 ring-blue-400/50 animate-pulse' : 'text-slate-500 hover:bg-slate-700 hover:text-blue-400'}`}
                    title={isSpeaking && activeType === 'answer' ? "Stop Reading" : "Read Answer"}
                  >
                    {isSpeaking && activeType === 'answer' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                  </button>
                  <RotateCcw size={16} />
                </div>
              </div>

              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && (
                  <div className="flex-shrink-0 w-full flex items-center justify-center mb-6">
                    {ansImgError ? (
                      <div className="flex flex-col items-center justify-center p-6 bg-white/5 rounded-lg border border-white/10 text-slate-500 gap-2">
                        <CircleAlert size={24} />
                        <span className="text-xs font-medium">Image not available</span>
                      </div>
                    ) : (
                      <div className="p-2 bg-white/5 rounded-lg border border-white/10 max-h-[200px] overflow-hidden">
                        <img 
                          src={currentCard.answerImage} 
                          alt="Answer" 
                          className="max-h-[180px] w-auto object-contain"
                          onError={() => setAnsImgError(true)}
                        />
                      </div>
                    )}
                  </div>
                )}

                {/* Render Answer as HTML */}
                <div 
                  className="text-xl md:text-3xl font-bold text-center text-white leading-relaxed drop-shadow-sm mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />

                {currentCard.explanation && (
                  <div className="w-full max-w-lg mt-auto mb-2 animate-in slide-in-from-bottom-2 fade-in duration-300">
                    <div className="bg-slate-900/50 border border-slate-600/30 rounded-lg overflow-hidden">
                      <div className="px-4 py-2 bg-slate-800/50 border-b border-slate-700/50 flex justify-between items-center">
                        <span className="text-emerald-400 font-bold text-[10px] uppercase tracking-wider flex items-center gap-1.5">
                          <Lightbulb size={12} /> Explanation
                        </span>
                        <button 
                          onClick={(e) => speak(stripHtml(currentCard.explanation || ''), 'explanation-main', 'explanation', e)}
                          className={`transition-colors p-1 rounded ${isSpeaking && activeType === 'explanation' ? 'text-emerald-400 bg-emerald-400/20 animate-pulse' : 'text-slate-400 hover:text-emerald-400'}`}
                          title={isSpeaking && activeType === 'explanation' ? "Stop Explanation" : "Read Explanation Only"}
                        >
                          {isSpeaking && activeType === 'explanation' ? <VolumeX size={12} /> : <Volume2 size={12} />}
                        </button>
                      </div>
                      {/* Render Explanation as HTML */}
                      <div 
                        className="p-4 text-slate-300 text-sm text-center leading-relaxed"
                        dangerouslySetInnerHTML={{ __html: currentCard.explanation }}
                      />
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center p-12 bg-white border-2 border-dashed border-slate-200 rounded-xl text-center w-full max-w-lg">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
            <Filter className="text-slate-300" size={32} />
          </div>
          <h3 className="text-lg font-bold text-slate-800 mb-2">No cards found</h3>
          <p className="text-slate-500 text-sm mb-6">Try selecting different topics or clear your filters.</p>
          <Button variant="outline" onClick={() => setSelectedCategories([])}>
            Clear Filters
          </Button>
        </div>
      )}

      {/* Navigation Controls */}
      <div className="flex items-center gap-6 mt-8 w-full justify-center max-w-md">
        <Button 
          variant="outline" 
          onClick={prevCard} 
          disabled={currentIndex === 0 || isAnimating || deck.length === 0}
          className="w-12 h-12 rounded-full border-slate-200 text-slate-400 hover:text-slate-600 hover:border-slate-300 disabled:opacity-30 bg-white shadow-sm"
        >
          <ChevronLeft size={24} />
        </Button>

        <Button 
          variant="primary" 
          onClick={flipCard}
          disabled={isAnimating || deck.length === 0}
          className={`
            h-12 px-6 rounded-full font-bold shadow-md transition-all active:scale-95 flex items-center gap-2
            ${isFlipped ? 'bg-slate-700 hover:bg-slate-600 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}
          `}
        >
          {isFlipped ? <><EyeOff size={18} /> Hide </> : <><Eye size={18} /> Show </>}
        </Button>

        <Button 
          variant="secondary" 
          onClick={nextCard} 
          disabled={currentIndex === deck.length - 1 || isAnimating || deck.length === 0}
          className="w-12 h-12 rounded-full bg-white text-blue-600 border border-slate-200 hover:bg-blue-50 hover:border-blue-200 disabled:opacity-30 shadow-sm"
        >
          <ChevronRight size={24} />
        </Button>
      </div>
    </div>
  );
};

