import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';
import { questions as importedQuestions } from './data';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);

  // Load custom questions AND overrides from local storage
  const [userQuestions, setUserQuestions] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_user_db');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load user database", e);
      return [];
    }
  });

  // Save to local storage whenever database changes
  useEffect(() => {
    localStorage.setItem('anatomy_user_db', JSON.stringify(userQuestions));
  }, [userQuestions]);

  const handleSaveQuestion = (q: Question) => {
    setUserQuestions(prev => {
      const exists = prev.find(item => item.id === q.id);
      if (exists) {
        return prev.map(item => item.id === q.id ? q : item);
      }
      return [q, ...prev];
    });
    setEditingQuestionId(null);
  };

  const handleDeleteQuestion = (id: string) => {
    if (confirm("Are you sure you want to delete/reset this question?")) {
      setUserQuestions(prev => prev.filter(q => q.id !== id));
    }
  };

  const startEditing = (id: string) => {
    setEditingQuestionId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  // Merge logic: Use user-edited version if it exists, otherwise use default
  const allQuestions = useMemo(() => {
    const userMap = new Map(userQuestions.map(q => [q.id, q]));

    // Start with all imported questions, replaced by user version if ID matches
    const merged = importedQuestions.map(q => userMap.get(q.id) || q);

    // Add brand new custom questions (those not in importedQuestions IDs)
    const importedIds = new Set(importedQuestions.map(q => q.id));
    const pureCustom = userQuestions.filter(q => !importedIds.has(q.id));

    return [...pureCustom, ...merged];
  }, [userQuestions]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
      <Header currentMode={currentMode} onModeChange={(mode) => {
        setCurrentMode(mode);
        if (mode !== AppMode.BUILDER) setEditingQuestionId(null);
      }} />

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} onEdit={startEditing} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block py-6' : 'hidden'}>
          <QuestionList data={allQuestions} onEdit={startEditing} onDelete={handleDeleteQuestion} userQuestions={userQuestions} />
        </div>
        <div className={currentMode === AppMode.BUILDER ? 'block py-6' : 'hidden'}>
          <QuestionBuilder 
            allQuestions={allQuestions}
            editingId={editingQuestionId}
            onSave={handleSaveQuestion}
            onCancel={() => {
              setEditingQuestionId(null);
              setCurrentMode(AppMode.LIST);
            }}
            existingCategories={categories}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import Button from './Button';
import { Plus, Save, X, Image as ImageIcon, FileText, HelpCircle, LayoutGrid, Pencil, Code, Info } from 'lucide-react';

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
      }
    }
  }, [editingId, allQuestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText || !formData.category) return;

    const finalQuestion: Question = {
      id: editingId || `custom-${Date.now()}`,
      ...formData
    };

    onSave(finalQuestion);

    if (!editingId) {
      setFormData(prev => ({
        ...prev,
        questionText: '',
        answerText: '',
        explanation: '',
        questionImage: '',
        answerImage: ''
      }));
    }
