          <div>
            <h2 className="text-xl font-bold flex items-center gap-2">
              {editingId ? <Pencil size={24} /> : <Plus size={24} />} 
              {editingId ? 'Edit Existing Question' : 'Create New Question'}
            </h2>
            <p className="text-sm opacity-90 mt-1 flex items-center gap-1">
              <Code size={14} /> Full HTML support enabled for all fields.
            </p>
          </div>
          <div className="bg-white/10 p-2 rounded-lg">
            <LayoutGrid size={24} />
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg flex gap-3 text-sm text-blue-800">
            <Info className="shrink-0" size={20} />
            <p>You can use HTML tags like <code>&lt;b&gt;bold&lt;/b&gt;</code>, <code>&lt;br&gt;</code> for new lines, or even <code>&lt;table&gt;</code> for complex data. The site will render them automatically.</p>
          </div>

          <div className="grid md:grid-cols-2 gap-6">
            <div className="col-span-2">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Category / Chapter</label>
              <input
                type="text"
                list="categories"
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value})}
                className="w-full p-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none font-medium"
                placeholder="Chapter name..."
