import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';
import { questions as importedQuestions } from './data';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingQuestionId, setEditingQuestionId] = useState<string | null>(null);

  const [userQuestions, setUserQuestions] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_user_db_v2');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load global vault", e);
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_user_db_v2', JSON.stringify(userQuestions));
  }, [userQuestions]);

  const handleSaveQuestion = (q: Question) => {
    setUserQuestions(prev => {
      const exists = prev.find(item => item.id === q.id);
      if (exists) {
        return prev.map(item => item.id === q.id ? q : item);
      }
      return [q, ...prev];
    });
    setEditingQuestionId(null);
  };

  const handleDeleteQuestion = (id: string) => {
    if (confirm("Permanently delete this record from the Global Vault?")) {
      setUserQuestions(prev => prev.filter(q => q.id !== id));
    }
  };

  const startEditing = (id: string) => {
    setEditingQuestionId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const allQuestions = useMemo(() => {
    const userMap = new Map(userQuestions.map(q => [q.id, q]));
    const merged = importedQuestions.map(q => userMap.get(q.id) || q);
    const importedIds = new Set(importedQuestions.map(q => q.id));
    const pureCustom = userQuestions.filter(q => !importedIds.has(q.id));
    return [...pureCustom, ...merged];
  }, [userQuestions]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  // Global Vault Functions
  const exportVault = () => {
    const dataStr = JSON.stringify(allQuestions, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const exportFileDefaultName = `ANATOMY_VAULT_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const importedData = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(importedData)) {
          setUserQuestions(importedData);
          alert("Vault Synchronized Successfully!");
        }
      } catch (err) {
        alert("Invalid Vault File Format.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
      <Header currentMode={currentMode} onModeChange={(mode) => {
        setCurrentMode(mode);
        if (mode !== AppMode.BUILDER) setEditingQuestionId(null);
      }} />

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} onEdit={startEditing} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block py-6' : 'hidden'}>
          <QuestionList 
            data={allQuestions} 
            onEdit={startEditing} 
            onDelete={handleDeleteQuestion} 
            userQuestions={userQuestions}
            onExport={exportVault}
            onImport={importVault}
          />
        </div>
        <div className={currentMode === AppMode.BUILDER ? 'block py-6' : 'hidden'}>
          <QuestionBuilder 
            allQuestions={allQuestions}
            editingId={editingQuestionId}
            onSave={handleSaveQuestion}
            onCancel={() => {
              setEditingQuestionId(null);
              setCurrentMode(AppMode.LIST);
            }}
            existingCategories={categories}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

