    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          // Merge imported data into existing user questions based on ID
          setUserQuestions(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q));
            return Array.from(currentMap.values());
          });
          alert("Vault Synchronized with Import File.");
        }
      } catch (err) {
        alert("Integrity Error: Invalid Backup File.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900">
      <Header currentMode={currentMode} onModeChange={(mode) => {
        setCurrentMode(mode);
        if (mode !== AppMode.BUILDER) setEditingQuestionId(null);
      }} />

      {/* Global Sync Indicator */}
      <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 pointer-events-none ${isSyncing ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0'}`}>
        <div className="bg-slate-900 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 border border-slate-700">
          <Zap size={16} className="text-blue-400 animate-pulse" />
          <span className="text-[10px] font-black uppercase tracking-widest">Vault Synced</span>
          <ShieldCheck size={16} className="text-emerald-400" />
        </div>
      </div>

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} onEdit={startEditing} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
